# Retrieve the fragment segmentation node from the parameter node
_parameter_node = logic.getParameterNode()
_fragment_seg_node = _parameter_node.GetNodeReference("FragmentSegmentation")
if _fragment_seg_node is None:
    # Fallback: search for a fracture segmentation node in the scene
    _fragment_seg_nodes = slicer.mrmlScene.GetNodesByClass("vtkMRMLSegmentationNode")
    _fragment_seg_node = None
    for _i in range(_fragment_seg_nodes.GetNumberOfItems()):
        _node = _fragment_seg_nodes.GetItemAsObject(_i)
        if _node.GetName().lower().find("fracture") != -1 or _node.GetName().lower().find("frac") != -1:
            _fragment_seg_node = _node
            break
    if _fragment_seg_node is None:
        raise RuntimeError("Fragment segmentation node not found. Ensure step 2-3 segmentation has been completed.")

cal_BBox(_fragment_seg_node)

print("[PelvicFracturePlanning] Step 'cb_step_8' completed.")
